import{_ as d,o as t,c as o,ae as c}from"./chunks/framework.DTwQaIIa.js";const h=JSON.parse('{"title":"命令与权限","description":"","frontmatter":{},"headers":[],"relativePath":"modules/forge/commands.md","filePath":"modules/forge/commands.md"}'),a={name:"modules/forge/commands.md"};function r(i,e,l,s,n,m){return t(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="命令与权限" tabindex="-1">命令与权限 <a class="header-anchor" href="#命令与权限" aria-label="Permalink to &quot;命令与权限&quot;">​</a></h1><p>EmakiForge 的所有命令都挂在根命令 <code>/emakiforge</code> 下面，日常使用可以用别名 <code>/eforge</code> 或 <code>/ef</code>。</p><h2 id="命令列表" tabindex="-1">命令列表 <a class="header-anchor" href="#命令列表" aria-label="Permalink to &quot;命令列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令</th><th>参数</th><th>做什么</th><th>权限</th></tr></thead><tbody><tr><td><code>/ef help</code></td><td>—</td><td>显示帮助信息</td><td>无</td></tr><tr><td><code>/ef forge</code></td><td><code>&lt;配方ID&gt;</code></td><td>打开指定配方的锻造界面</td><td><code>emakiforge.use</code></td></tr><tr><td><code>/ef book</code></td><td>—</td><td>打开配方书</td><td><code>emakiforge.book</code></td></tr><tr><td><code>/ef reload</code></td><td>—</td><td>重载所有配置和资源文件</td><td><code>emakiforge.reload</code></td></tr><tr><td><code>/ef list recipe</code></td><td>—</td><td>列出所有已加载的配方</td><td><code>emakiforge.admin</code></td></tr></tbody></table><h3 id="命令详解" tabindex="-1">命令详解 <a class="header-anchor" href="#命令详解" aria-label="Permalink to &quot;命令详解&quot;">​</a></h3><p><strong><code>/ef forge &lt;配方ID&gt;</code></strong></p><p>打开指定配方的锻造 GUI。玩家把图纸和材料放进对应槽位，点确认按钮就能锻造。配方 ID 就是配方 YAML 文件里的 <code>id</code> 字段。</p><p><strong><code>/ef book</code></strong></p><p>打开配方书界面，列出当前玩家有权限查看的所有配方，支持翻页。适合给玩家一个入口来浏览和选择配方，而不用记住每个配方的 ID。</p><p><strong><code>/ef reload</code></strong></p><p>重载以下资源：</p><ul><li><code>config.yml</code> 主配置</li><li><code>lang/</code> 语言文件</li><li><code>gui/</code> GUI 配置</li><li><code>recipes/</code> 配方文件</li><li><code>blueprints/</code> 图纸文件</li><li><code>materials/</code> 材料文件</li></ul><p>手动改了文件之后需要执行这个命令才能生效。</p><h2 id="权限节点" tabindex="-1">权限节点 <a class="header-anchor" href="#权限节点" aria-label="Permalink to &quot;权限节点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>权限节点</th><th>说明</th><th>默认</th></tr></thead><tbody><tr><td><code>emakiforge.use</code></td><td>使用锻造功能</td><td><code>true</code></td></tr><tr><td><code>emakiforge.book</code></td><td>打开配方书</td><td><code>true</code></td></tr><tr><td><code>emakiforge.reload</code></td><td>重载配置</td><td><code>op</code></td></tr><tr><td><code>emakiforge.admin</code></td><td>管理员权限（包含列表查看等）</td><td><code>op</code></td></tr></tbody></table><p><code>emakiforge.use</code> 和 <code>emakiforge.book</code> 默认对所有玩家开放。管理相关的权限默认只有 OP 才有。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>除了这些全局权限，你还可以在配方文件里通过 <code>permission</code> 字段给单个配方设置独立权限，或者在 <code>conditions</code> 里用 <code>type: permission</code> 做更细粒度的控制。比如某个高级配方只有特定等级的玩家才能用。</p></div>',17)])])}const f=d(a,[["render",r]]);export{h as __pageData,f as default};
